import json
import os

def lambda_handler(event, context):
    """
    Example Lambda function handler.
    This function demonstrates a simple response for a microservice endpoint.
    """
    print(f"Received event: {json.dumps(event)}")

    # You would typically process the event here, interact with other services
    # using the permissions granted by the shared IAM role.

    # Example: Check for an environment variable
    service_name = os.environ.get('SERVICE_NAME', 'Unknown Service')

    response_body = {
        "message": f"Hello from {service_name}!",
        "input_event": event,
        "lambda_request_id": context.aws_request_id
    }

    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/json'
        },
        'body': json.dumps(response_body)
    }

